"use client";

import { useEffect, useRef, useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { RefreshCw, ExternalLink } from "lucide-react";
import { MARKET_SOURCES } from "../sources";

export default function ForexRatesPage() {
  const [isLoadingVND, setIsLoadingVND] = useState(true);
  const [isLoadingFX, setIsLoadingFX] = useState(true);
  const wrapVnd = useRef<HTMLDivElement | null>(null);
  const wrapFx = useRef<HTMLDivElement | null>(null);
  const [vndInView, setVndInView] = useState(false);
  const [fxInView, setFxInView] = useState(false);

  const srcFX = MARKET_SOURCES.FX;

  useEffect(() => {
    const ov = new IntersectionObserver((e) => { if (e[0].isIntersecting) { setVndInView(true); ov.disconnect(); } }, { rootMargin: "200px" });
    if (wrapVnd.current) ov.observe(wrapVnd.current);
    const ofx = new IntersectionObserver((e) => { if (e[0].isIntersecting) { setFxInView(true); ofx.disconnect(); } }, { rootMargin: "200px" });
    if (wrapFx.current) ofx.observe(wrapFx.current);
    return () => { ov.disconnect(); ofx.disconnect(); };
  }, []);

  return (
    <section className="relative  py-25  overflow-hidden">
      {/* Background: use global theme background; remove fixed white overlays */}

      <div className="relative max-w-[1600px] mx-auto px-4 md:px-6 space-y-8">

        {/* Section: Forex cross rates */}
        <div className="space-y-3">
          <div className="inline-flex items-center gap-2">
            <Badge variant="outline" className="border-[#7042E1]/30 text-[#7042E1]">Forex</Badge>
          </div>
          <h2 className="text-3xl sm:text-4xl md:text-5xl font-black tracking-tight leading-[1.1] bg-gradient-to-tr from-[#5C278B] to-[#A084FB] bg-clip-text leading-relaxed text-transparent">Bảng Cross-Rates Forex</h2>
          <div className="flex items-center gap-2">
            <Button size="sm" variant="outline" className="border-border" onClick={() => { setIsLoadingFX(true); const f = document.getElementById("fx-board") as HTMLIFrameElement | null; if (f) f.src = srcFX; }}>
              <RefreshCw className="h-4 w-4 mr-2" /> Làm mới
            </Button>
            <Button size="sm" variant="outline" className="border-border" asChild>
              <a href={srcFX} target="_blank" rel="noopener noreferrer"><ExternalLink className="h-4 w-4 mr-2" /> Mở tab mới</a>
            </Button>
          </div>
        </div>

        {/* Card 2: Forex cross rates */}
        <div ref={wrapFx} className={`relative rounded-[28px] transition-all`}>
          <Card className="rounded-[26px] overflow-hidden border border-[rgba(112,66,225,0.3)] dark:border-[rgba(160,132,251,0.6)] bg-card/60 dark:bg-[rgba(255,255,255,0.05)] backdrop-blur-md px-4 py-4 shadow-[0_0_10px_rgba(112,66,225,0.2)] dark:shadow-[0_0_15px_rgba(160,132,251,0.4)] transition-all duration-300 hover:shadow-[0_0_20px_rgba(112,66,225,0.3)] dark:hover:shadow-[0_0_25px_rgba(160,132,251,0.7)]">
            <CardContent className="p-0">
              {isLoadingFX && (
                <div className="absolute inset-0 z-10 grid place-items-center bg-background/70 backdrop-blur-sm">
                  <div className="w-full max-w-[720px] px-8">
                    <Skeleton className="h-8 w-1/3 mb-4" />
                    <Skeleton className="h-[44vh] md:h-[54vh] rounded-xl" />
                  </div>
                </div>
              )}
              <iframe
                id="fx-board"
                src={fxInView ? srcFX : undefined}
                title="Live Forex Cross Rates"
                onLoad={() => setIsLoadingFX(false)}
                className={`w-full rounded-[26px] h-[50vh]  bg-card`}
                allow="clipboard-read; clipboard-write; fullscreen; geolocation; camera; microphone; display-capture; autoplay; allow-same-origin"
                referrerPolicy="no-referrer-when-downgrade"
                loading="lazy"
                sandbox="allow-scripts allow-popups allow-forms; allow-same-origin"
              />
            </CardContent>
          </Card>
        </div>
      </div>
    </section>
  );
}

import { LandingPage } from "@/components/landing/landingPage";

import Image from "next/image";

export default function Home() {
  return (
    <>

  <LandingPage/>
    </>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useAuthServer } from "@/hooks/useAuthServer";
import { getPlanName } from "@/components/user/header/planBadge";
import { Card } from "@/components/ui/card";
import { Lock } from "lucide-react";
import { PortfolioSectionCard } from "@/components/portfolio/portfolioSectionCard";
import { PerformanceChart } from "@/components/portfolio/performanceChart";
import { WeightPieChart } from "@/components/portfolio/weightPieChart";
import { StopLossTargetChart } from "@/components/portfolio/stopLossTargetChart";
import { PortfolioTable } from "@/components/portfolio/portfolioTable";
import { SupportReasons } from "@/components/portfolio/supportReasons";
import { Signals } from "@/components/portfolio/signals";
import {
  PORTFOLIO_TIERS,
  type PortfolioTier,
  TIER_LABELS,
  TIER_DESCRIPTIONS,
  canAccessTier,
  tierToPlanName,
} from "@/lib/constants/portfolio";
import { usePortfolioQuery } from "@/hooks/usePortfolioQuery";
import { usePortfolioData } from "@/hooks/usePortfolioData";
import { PortfolioLoadingState } from "@/components/portfolio/portfolioLoadingState";
import { PortfolioErrorState } from "@/components/portfolio/portfolioErrorState";
import { getPlans, type PlanApiResponse, type PlanFieldVisibility } from "@/lib/services/plansService";
import { calculatePortfolioMetrics } from "@/lib/utils/portfolioCalculations";

const TAB_CONFIG: Array<{
  key: PortfolioTier;
  label: string;
  description: string;
}> = [
  {
    key: PORTFOLIO_TIERS.COMMUNITY,
    label: TIER_LABELS[PORTFOLIO_TIERS.COMMUNITY],
    description: TIER_DESCRIPTIONS[PORTFOLIO_TIERS.COMMUNITY],
  },
  {
    key: PORTFOLIO_TIERS.TITAN,
    label: TIER_LABELS[PORTFOLIO_TIERS.TITAN],
    description: TIER_DESCRIPTIONS[PORTFOLIO_TIERS.TITAN],
  },
  {
    key: PORTFOLIO_TIERS.GOLD,
    label: TIER_LABELS[PORTFOLIO_TIERS.GOLD],
    description: TIER_DESCRIPTIONS[PORTFOLIO_TIERS.GOLD],
  },
  {
    key: PORTFOLIO_TIERS.PREMIUM,
    label: TIER_LABELS[PORTFOLIO_TIERS.PREMIUM],
    description: TIER_DESCRIPTIONS[PORTFOLIO_TIERS.PREMIUM],
  },
];

/**
 * QUAN TRỌNG — SỬA LỖI KIẾN TRÚC:
 * Đây chỉ là default cho các field TEXT (title/description) khi BE không trả.
 * KHÔNG được đặt default = true cho bất kỳ field "*Enabled" nào ở đây.
 * Lý do: nếu BE (vì bug hoặc vì admin chưa từng bật) không trả 1 key "*Enabled"
 * nào đó trong fieldVisibilities, object bị thiếu key đó (undefined) chứ
 * không phải false. Nếu ta merge với default = true, undefined sẽ bị ghi đè
 * thành "true" => hiện nhầm block chưa được phép hiện. Đây chính là nguyên
 * nhân khiến các gói Free/Gold/Titan hiển thị sai lệch so với checkbox admin.
 */
const DEFAULT_VISIBILITY_TEXT = {
  dashboardTitle: "Danh mục đầu tư",
  dashboardDescription: "Theo dõi dữ liệu danh mục theo cấu hình của từng gói.",
  performanceTitle: "Hiệu suất danh mục vs VNINDEX",
  performanceDescription: "Biểu đồ hiệu suất danh mục so với VNINDEX theo các kỳ cập nhật.",
  portfolioCompositionTitle: "Tỷ trọng danh mục",
  portfolioCompositionDescription: "Phân bổ tỷ trọng các mã trong danh mục.",
  targetInfoTitle: "Tín hiệu mua/bán",
  targetInfoDescription: "Các điểm nhấn giao dịch gần nhất theo danh mục.",
  analysisTitle: "Lý do hỗ trợ",
  analysisDescription: "Luận điểm đầu tư và các ghi chú phân tích cho từng mã.",
  portfolioTableTitle: "Bảng danh mục",
  portfolioTableDescription: "Chi tiết danh mục hiện tại.",
} as const;

/**
 * Các field "*Enabled" PHẢI mặc định false khi bị thiếu trong response.
 * FE không tự quyết định "cứ thiếu thì coi như bật" — nếu BE không xác nhận
 * rõ ràng là bật (true), FE phải coi là ẩn. Đây là nguyên tắc an toàn:
 * fail-closed thay vì fail-open, đúng với tinh thần "BE là nguồn sự thật
 * duy nhất, FE chỉ render thuần theo response".
 */
function getMergedVisibility(fieldVisibilities?: PlanFieldVisibility | null): PlanFieldVisibility {
  return {
    dashboardEnabled: fieldVisibilities?.dashboardEnabled === true,
    performanceChartEnabled: fieldVisibilities?.performanceChartEnabled === true,
    portfolioCompositionEnabled: fieldVisibilities?.portfolioCompositionEnabled === true,
    targetInfoEnabled: fieldVisibilities?.targetInfoEnabled === true,
    analysisCardsEnabled: fieldVisibilities?.analysisCardsEnabled === true,
    portfolioTableEnabled: fieldVisibilities?.portfolioTableEnabled === true,
    dashboardTitle: fieldVisibilities?.dashboardTitle || DEFAULT_VISIBILITY_TEXT.dashboardTitle,
    dashboardDescription: fieldVisibilities?.dashboardDescription || DEFAULT_VISIBILITY_TEXT.dashboardDescription,
    performanceTitle: fieldVisibilities?.performanceTitle || DEFAULT_VISIBILITY_TEXT.performanceTitle,
    performanceDescription: fieldVisibilities?.performanceDescription || DEFAULT_VISIBILITY_TEXT.performanceDescription,
    portfolioCompositionTitle: fieldVisibilities?.portfolioCompositionTitle || DEFAULT_VISIBILITY_TEXT.portfolioCompositionTitle,
    portfolioCompositionDescription: fieldVisibilities?.portfolioCompositionDescription || DEFAULT_VISIBILITY_TEXT.portfolioCompositionDescription,
    targetInfoTitle: fieldVisibilities?.targetInfoTitle || DEFAULT_VISIBILITY_TEXT.targetInfoTitle,
    targetInfoDescription: fieldVisibilities?.targetInfoDescription || DEFAULT_VISIBILITY_TEXT.targetInfoDescription,
    analysisTitle: fieldVisibilities?.analysisTitle || DEFAULT_VISIBILITY_TEXT.analysisTitle,
    analysisDescription: fieldVisibilities?.analysisDescription || DEFAULT_VISIBILITY_TEXT.analysisDescription,
    portfolioTableTitle: fieldVisibilities?.portfolioTableTitle || DEFAULT_VISIBILITY_TEXT.portfolioTableTitle,
    portfolioTableDescription: fieldVisibilities?.portfolioTableDescription || DEFAULT_VISIBILITY_TEXT.portfolioTableDescription,
  };
}

function EmptyPortfolioState({ title }: { title: string }) {
  return (
    <Card className="p-8 text-center">
      <h3 className="text-lg font-semibold">{title}</h3>
      <p className="mt-2 text-sm text-muted-foreground">
        Chưa có dữ liệu danh mục. Admin sẽ cập nhật sớm nhất có thể.
      </p>
    </Card>
  );
}

export default function PortfolioClientBlocks() {
  const { user, checkProfile } = useAuthServer();
  const [activeTab, setActiveTab] = useState<PortfolioTier>(PORTFOLIO_TIERS.COMMUNITY);

  useEffect(() => {
    checkProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const planSlug = useMemo(() => {
    const raw = getPlanName(user?.plan ?? null);
    if (raw === "free") return PORTFOLIO_TIERS.COMMUNITY;
    return raw as PortfolioTier;
  }, [user?.plan]);

  const { data: plans = [] } = useQuery<PlanApiResponse[]>({
    queryKey: ["plans"],
    queryFn: getPlans,
    staleTime: 10 * 60 * 1000,
  });

  const planByTier = useMemo(() => {
    const map = new Map<PortfolioTier, PlanApiResponse>();
    for (const plan of plans) {
      // .trim() thêm vào để tránh lệch do khoảng trắng thừa từ BE,
      // ngoài .toLowerCase() đã có sẵn.
      const normalizedSlug = (plan.slug ?? "").toLowerCase().trim();
      if (normalizedSlug === "free" || normalizedSlug === "community") map.set(PORTFOLIO_TIERS.COMMUNITY, plan);
      if (normalizedSlug === "titan") map.set(PORTFOLIO_TIERS.TITAN, plan);
      if (normalizedSlug === "gold") map.set(PORTFOLIO_TIERS.GOLD, plan);
      if (normalizedSlug === "premium") map.set(PORTFOLIO_TIERS.PREMIUM, plan);
    }
    return map;
  }, [plans]);

  useEffect(() => {
    const matchingTab = TAB_CONFIG.find((tab) => tab.key === planSlug);
    if (matchingTab) {
      setActiveTab(matchingTab.key);
    } else {
      const firstAllowed = TAB_CONFIG.find((tab) => canAccessTier(planSlug, tab.key));
      if (firstAllowed) {
        setActiveTab(firstAllowed.key);
      }
    }
  }, [planSlug]);

  const planName = useMemo(() => tierToPlanName(activeTab), [activeTab]);

  /**
   * SỬA: không còn fallback ngầm "?? 'Premium'".
   * Nếu tierToPlanName trả về null (lỗi mapping cho 1 tier nào đó), trước
   * đây FE sẽ âm thầm gọi API portfolio của Premium — khiến gói khác hiển
   * thị nhầm data của Premium mà không ai biết. Giờ nếu planName null thì
   * đơn giản là không fetch, và render sẽ báo lỗi rõ ràng thay vì che giấu.
   */
  const shouldFetch = planName !== null;
  const queryPlanName = planName ?? "Free";

  const {
    data: portfolio,
    isLoading,
    error,
  } = usePortfolioQuery(queryPlanName, { enabled: shouldFetch });

  const {
    performanceData,
    weightData,
    stopLossItems,
    tableRows,
    supportReasonsData,
    signalsData = [],
  } = usePortfolioData(portfolio);

  const { categories: performanceCategories = [], reco: performanceReco = [], index: performanceIndex = [] } = performanceData || {};

  const portfolioMetrics = useMemo(() => {
    if (!portfolio?.stocks?.length || !portfolio?.information?.length) return [];
    const metrics = calculatePortfolioMetrics(portfolio.stocks, portfolio.information);
    return [
      { name: "Tỷ số Sharpe", value: metrics.sharpeRatio },
      { name: "Beta", value: metrics.beta },
      { name: "Giá trị alpha danh mục", value: metrics.alpha },
      { name: "Rủi ro của danh mục", value: metrics.risk },
      { name: "Tỷ lệ chiết khấu từ đỉnh", value: metrics.maxDrawdown },
      { name: "Lợi nhuận VNINDEX", value: metrics.vnindexReturn },
      { name: "Lợi nhuận danh mục", value: metrics.portfolioReturn },
    ];
  }, [portfolio?.stocks, portfolio?.information]);

  const activePlan = planByTier.get(activeTab);
  const visibility = getMergedVisibility(activePlan?.fieldVisibilities);

  const hasPerformanceData =
    performanceCategories.length > 0 &&
    performanceReco.length > 0 &&
    performanceIndex.length > 0;

  const renderTabContent = () => {
    if (!shouldFetch) {
      // planName bị null do lỗi mapping tier -> plan, KHÔNG fallback ngầm
      // sang Premium nữa. Báo lỗi rõ ràng để dev/QA phát hiện ngay.
      return <PortfolioErrorState />;
    }
    if (isLoading) {
      return <PortfolioLoadingState />;
    }
    if (error) {
      return <PortfolioErrorState />;
    }

    if (!activePlan || !activePlan.fieldVisibilities) {
      return <EmptyPortfolioState title={activePlan?.name || "Danh mục đầu tư"} />;
    }

    const sectionCards = [];

    const showPerformance = visibility.performanceChartEnabled;
    const showComposition = visibility.portfolioCompositionEnabled; // Derived from stocks, toggle purely by Plan
    const showTable = visibility.portfolioTableEnabled;
    const showReasons = visibility.analysisCardsEnabled;
    const showStopLoss = visibility.targetInfoEnabled; // Derived from stocks, toggle purely by Plan
    const showSignals = visibility.targetInfoEnabled;

    if (showPerformance) {
      sectionCards.push(
        <PortfolioSectionCard
          key="performance"
          title={visibility.performanceTitle}
          description={visibility.performanceDescription}
          hasData={hasPerformanceData}
        >
          <PerformanceChart
            categories={performanceData.categories}
            reco={performanceData.reco}
            index={performanceData.index}
          />
        </PortfolioSectionCard>
      );
    }

    if (showComposition) {
      sectionCards.push(
        <PortfolioSectionCard
          key="composition"
          title={visibility.portfolioCompositionTitle}
          description={visibility.portfolioCompositionDescription}
          hasData={weightData.length > 0}
        >
          <WeightPieChart data={weightData} />
        </PortfolioSectionCard>
      );
    }

    if (showTable) {
      sectionCards.push(
        <PortfolioSectionCard
          key="table"
          className="p-6 space-y-4"
          title={visibility.portfolioTableTitle}
          description={visibility.portfolioTableDescription}
          hasData={tableRows.length > 0}
        >
          <PortfolioTable rows={tableRows} />
        </PortfolioSectionCard>
      );
    }

    if (showReasons) {
      sectionCards.push(
        <PortfolioSectionCard
          key="reasons"
          className="p-6 space-y-4"
          title={visibility.analysisTitle}
          description={visibility.analysisDescription}
          hasData={supportReasonsData.length > 0}
        >
          <SupportReasons rows={supportReasonsData} />
        </PortfolioSectionCard>
      );
    }

    if (showStopLoss || showSignals) {
      sectionCards.push(
        <div key="advanced-grid" className="grid grid-cols-1 xl:grid-cols-2 gap-6">
          {showStopLoss && (
            <PortfolioSectionCard
              title="Giá mục tiêu vs Giá dừng lỗ"
              className="p-6 space-y-4"
              hasData={stopLossItems.length > 0}
            >
              <StopLossTargetChart items={stopLossItems} />
            </PortfolioSectionCard>
          )}
          {showSignals && (
            <PortfolioSectionCard
              title={visibility.targetInfoTitle}
              description={visibility.targetInfoDescription}
              className="p-6 space-y-4"
              hasData={signalsData.length > 0}
            >
              <Signals items={signalsData} />
            </PortfolioSectionCard>
          )}
        </div>
      );
    }

    return <div className="space-y-6">{sectionCards}</div>;
  };

  return (
    <section className="mx-auto max-w-screen-2xl px-4 sm:px-6 md:px-10 lg:px-14 pt-28 pb-16 space-y-8">
      <div className="space-y-1">
        <h1 className="text-3xl sm:text-4xl font-bold">{visibility.dashboardTitle}</h1>
        <p className="text-muted-foreground">{visibility.dashboardDescription}</p>
      </div>

      <div className="inline-flex flex-wrap items-center justify-start gap-2 rounded-2xl border border-border/60 bg-white/80 px-2 py-2 shadow-sm backdrop-blur dark:border-white/10 dark:bg-white/5">
        {TAB_CONFIG.map((tab) => {
          const locked = !canAccessTier(planSlug, tab.key);
          const isActive = activeTab === tab.key;

          return (
            <button
              key={tab.key}
              type="button"
              disabled={locked}
              onClick={() => setActiveTab(tab.key)}
              className={`px-3 sm:px-4 py-2 text-xs sm:text-sm font-semibold rounded-full transition-all flex items-center gap-2 ${
                isActive
                  ? "bg-gradient-to-r from-[#7042E1] to-[#A084FB] text-white shadow-[0_6px_18px_rgba(112,66,225,0.25)]"
                  : "text-foreground/70 hover:text-foreground"
              } ${locked ? "opacity-55 cursor-not-allowed" : ""}`}
            >
              {tab.label}
              {locked && <Lock className="h-4 w-4 opacity-70" />}
            </button>
          );
        })}
      </div>

      {renderTabContent()}
    </section>
  );
}

"use client";

import { useEffect, useMemo } from "react";
import { useRouter } from "next/navigation";
import { TrendingUp, Activity } from "lucide-react";
import { Card } from "@/components/ui/card";
import { getPlanName } from "@/components/user/header/planBadge";
import { useAuthServer } from "@/hooks/useAuthServer";
import { SupportReasons } from "@/components/portfolio/supportReasons";
import { Signals } from "@/components/portfolio/signals";
import { PortfolioLoadingState } from "@/components/portfolio/portfolioLoadingState";
import { PortfolioErrorState } from "@/components/portfolio/portfolioErrorState";
import { PortfolioAccessDenied } from "@/components/portfolio/portfolioAccessDenied";
import { PORTFOLIO_TIERS, type PortfolioTier } from "@/lib/constants/portfolio";
import { getAllowedPlansForTier } from "@/lib/utils/portfolioAccess";
import { usePortfolioQuery } from "@/hooks/usePortfolioQuery";
import { usePortfolioData } from "@/hooks/usePortfolioData";
import { useQuery } from "@tanstack/react-query";
import { getPlans, type PlanApiResponse, type PlanFieldVisibility } from "@/lib/services/plansService";

const DEFAULT_VISIBILITY: PlanFieldVisibility = {
  dashboardEnabled: true,
  performanceChartEnabled: true,
  portfolioCompositionEnabled: true,
  targetInfoEnabled: true,
  analysisCardsEnabled: true,
  portfolioTableEnabled: true,
};

function getMergedVisibility(fieldVisibilities?: PlanFieldVisibility | null): PlanFieldVisibility {
  return {
    ...DEFAULT_VISIBILITY,
    ...fieldVisibilities,
  };
}

function SectionEmptyState({ message }: { message?: string }) {
  return (
    <div className="flex flex-col items-center justify-center py-8 text-center text-muted-foreground">
      <p className="text-sm">{message || "Chưa có dữ liệu. Admin sẽ cập nhật sớm nhất có thể."}</p>
    </div>
  );
}

export default function GoldPortfolioPage() {
  const router = useRouter();
  const { user, checkProfile, isLoading: isAuthLoading } = useAuthServer();
  const planSlug = useMemo(() => getPlanName(user?.plan ?? null), [user?.plan]);

  const { data: plans = [] } = useQuery<PlanApiResponse[]>({
    queryKey: ["plans"],
    queryFn: getPlans,
    staleTime: 10 * 60 * 1000,
  });

  const activePlan = useMemo(() => {
    return plans.find((p) => (p.slug ?? "").toLowerCase() === "gold");
  }, [plans]);

  const visibility = useMemo(() => getMergedVisibility(activePlan?.fieldVisibilities), [activePlan]);

  const {
    data: portfolio,
    isLoading,
    error,
  } = usePortfolioQuery("Gold");

  useEffect(() => {
    checkProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const allowedPlans = useMemo(() => getAllowedPlansForTier(PORTFOLIO_TIERS.GOLD), []);
  const hasAccess = allowedPlans.includes(planSlug as PortfolioTier);

  useEffect(() => {
    if (isAuthLoading) return;
    if (!user) return;
    if (!hasAccess) {
      router.replace("/portfolio");
    }
  }, [user, hasAccess, router, isAuthLoading]);

  // Sử dụng custom hook để xử lý tất cả tính toán
  const {
    supportReasonsData,
    signalsData,
  } = usePortfolioData(portfolio);

  // Early return sau khi tất cả hooks đã được gọi (tuân thủ Rules of Hooks)
  if (!hasAccess) {
    return <PortfolioAccessDenied tier={PORTFOLIO_TIERS.GOLD} />;
  }

  if (isLoading) {
    return (
      <section className="mx-auto max-w-screen-2xl px-4 sm:px-6 md:px-10 lg:px-14 pt-28 pb-16 space-y-8">
        <PortfolioLoadingState />
      </section>
    );
  }

  if (error) {
    return (
      <section className="mx-auto max-w-screen-2xl px-4 sm:px-6 md:px-10 lg:px-14 pt-28 pb-16 space-y-8">
        <PortfolioErrorState />
      </section>
    );
  }

  const sectionCards = [
    supportReasonsData.length > 0 && (
      <Card key="analysis" className="p-6 space-y-4">
        <div className="flex items-center gap-2">
          <TrendingUp className="h-5 w-5 text-purple-500" />
          <div>
            <h3 className="font-semibold text-lg">
