function getMergedVisibility(fieldVisibilities?: PlanFieldVisibility | null): PlanFieldVisibility {
  return {
    ...DEFAULT_VISIBILITY,
    ...fieldVisibilities,
  };
}

function SectionEmptyState({ message }: { message?: string }) {
