export default function PremiumPortfolioPage() {
  const router = useRouter();
  const { user, checkProfile, isLoading: isAuthLoading } = useAuthServer();
  const planSlug = useMemo(() => getPlanName(user?.plan ?? null), [user?.plan]);

  const { data: plans = [] } = useQuery<PlanApiResponse[]>({
    queryKey: ["plans"],
    queryFn: getPlans,
    staleTime: 10 * 60 * 1000,
  });

  const activePlan = useMemo(() => {
    return plans.find((p) => (p.slug ?? "").toLowerCase() === "premium");
  }, [plans]);

  const visibility = useMemo(() => getMergedVisibility(activePlan?.fieldVisibilities), [activePlan]);

  const {
    data: portfolio,
    isLoading,
    error,
  } = usePortfolioQuery("Premium");

  useEffect(() => {
    checkProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (isAuthLoading) return;
    if (!user) return;
    if (planSlug !== PORTFOLIO_TIERS.PREMIUM) {
      router.replace("/portfolio");
    }
  }, [user, planSlug, router, isAuthLoading]);

  // Sử dụng custom hook để xử lý tất cả tính toán
  const {
    performanceData,
    weightData,
    stopLossItems,
    tableRows,
    supportReasonsData,
  } = usePortfolioData(portfolio);

  // Destructure để tránh re-render không cần thiết
  const { categories: performanceCategories = [], reco: performanceReco = [], index: performanceIndex = [] } = performanceData || {};

  // Tính toán metrics cho BasicsChart - phải đặt trước early return
  const portfolioMetrics = useMemo(() => {
    if (!portfolio?.stocks?.length || !portfolio?.information?.length) {
      return [];
    }
    const metrics = calculatePortfolioMetrics(portfolio.stocks, portfolio.information);
    
    return [
      { name: "Tỷ số Sharpe", value: metrics.sharpeRatio },
      { name: "Beta", value: metrics.beta },
      { name: "Giá trị alpha danh mục", value: metrics.alpha },
      { name: "Rủi ro của danh mục", value: metrics.risk },
      { name: "Tỷ lệ chiết khấu từ đỉnh", value: metrics.maxDrawdown },
      { name: "Lợi nhuận VNINDEX", value: metrics.vnindexReturn },
      { name: "Lợi nhuận danh mục", value: metrics.portfolioReturn },
    ];
  }, [portfolio?.stocks, portfolio?.information]);

  // Early return sau khi tất cả hooks đã được gọi (tuân thủ Rules of Hooks)
  const allowedPlans = useMemo(() => getAllowedPlansForTier(PORTFOLIO_TIERS.PREMIUM), []);
  const hasAccess = planSlug === PORTFOLIO_TIERS.PREMIUM;

  if (!hasAccess) {
    return <PortfolioAccessDenied tier={PORTFOLIO_TIERS.PREMIUM} />;
  }

  if (isLoading) {
    return (
      <section className="mx-auto max-w-screen-2xl px-4 sm:px-6 md:px-10 lg:px-14 pt-28 pb-16 space-y-8">
        <PortfolioLoadingState />
      </section>
    );
  }

  if (error) {
    return (
      <section className="mx-auto max-w-screen-2xl px-4 sm:px-6 md:px-10 lg:px-14 pt-28 pb-16 space-y-8">
        <PortfolioErrorState />
      </section>
    );
  }

  const sectionCards = [
    performanceCategories.length > 0 && performanceReco.length > 0 && performanceIndex.length > 0 && (
      <Card key="performance" className="p-6 space-y-6">
        <h3 className="font-semibold text-lg">
          {visibility.performanceTitle || "Hiệu suất danh mục vs VNINDEX"}
        </h3>
        {visibility.performanceDescription && (
          <p className="text-sm text-muted-foreground">{visibility.performanceDescription}</p>
        )}
        <PerformanceChart categories={performanceCategories} reco={performanceReco} index={performanceIndex} />
      </Card>
    ),

    weightData.length > 0 && (
      <Card key="composition" className="p-6 space-y-6">
        <h3 className="font-semibold text-lg">
          {visibility.portfolioCompositionTitle || "Tỷ trọng danh mục"}
        </h3>
        {visibility.portfolioCompositionDescription && (
          <p className="text-sm text-muted-foreground">{visibility.portfolioCompositionDescription}</p>
        )}
        <WeightPieChart data={weightData} />
      </Card>
    ),

    (stopLossItems.length > 0 || portfolioMetrics.length > 0) && (
      <div key="composition-details" className={`grid grid-cols-1 ${stopLossItems.length > 0 && portfolioMetrics.length > 0 ? 'xl:grid-cols-2' : ''} gap-6`}>
        {stopLossItems.length > 0 && (
          <Card className="p-6 space-y-4">
            <h3 className="font-semibold text-lg">Giá mục tiêu vs Giá dừng lỗ (tương đối)</h3>
            <StopLossTargetChart items={stopLossItems} />
          </Card>
        )}

        {portfolioMetrics.length > 0 && (
          <Card className="p-6 space-y-4">
            <h3 className="font-semibold text-lg">Thông tin cơ bản danh mục</h3>
            <BasicsChart metrics={portfolioMetrics} />
          </Card>
        )}
      </div>
    ),

    supportReasonsData.length > 0 && (
      <Card key="analysis" className="p-6 space-y-4">
        <div className="flex items-center justify-between gap-2">
          <div>
            <h3 className="font-semibold text-lg">
              {visibility.analysisTitle || "Lý do hỗ trợ"}
            </h3>
            <p className="text-sm text-muted-foreground">
              {visibility.analysisDescription || "Dạng timeline, mỗi mã gói gọn trong card riêng."}
            </p>
          </div>
        </div>
        <SupportReasons rows={supportReasonsData} />
      </Card>
    ),

    tableRows.length > 0 && (
      <Card key="table" className="p-4 overflow-hidden">
        <div className="flex items-center justify-between mb-3">
          <div>
            <h3 className="font-semibold text-base">
              {visibility.portfolioTableTitle || "Bảng danh mục (tham chiếu)"}
            </h3>
            <p className="text-sm text-muted-foreground">
              {visibility.portfolioTableDescription || "Thể hiện lại các cột chính: mã, ngành, ngày mua, giá vốn, giá thị trường, tỷ trọng, lãi/lỗ, dừng lỗ, mục tiêu, beta, MDD."}
            </p>
          </div>
        </div>
        <PortfolioTable rows={tableRows} />
      </Card>
    ),
  ].filter(Boolean);

  return (
    <section className="mx-auto max-w-screen-2xl px-4 sm:px-6 md:px-10 lg:px-14 pt-28 pb-16 space-y-8">
      <div className="space-y-1">
        <h1 className="text-3xl sm:text-4xl font-bold">
          {visibility.dashboardTitle || "Danh mục Premium"}
        </h1>
        <p className="text-muted-foreground">
          {visibility.dashboardDescription || "Toàn bộ dashboard và bảng chi tiết cho gói Premium."}
        </p>
      </div>

      {sectionCards.length > 0 ? (
        <div className="space-y-6">{sectionCards}</div>
      ) : (
        <div className="flex flex-col items-center justify-center py-16 text-center border rounded-lg bg-card/50">
          <h3 className="text-xl font-semibold mb-2">{activePlan?.name || "Danh mục Premium"}</h3>
          <p className="text-muted-foreground">
            Chưa có mục nào được hiển thị. Admin sẽ cấu hình và cập nhật sớm nhất.
          </p>
        </div>
      )}
    </section>
  );
}

