  );
}

"use client";

import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  useReactTable,
  getPaginationRowModel,
  SortingState,
  getSortedRowModel,
  ColumnFiltersState,
  getFilteredRowModel,
} from "@tanstack/react-table";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { useState } from "react";
import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight, Search } from "lucide-react";
import { Input } from "@/components/ui/input";
import { motion } from "framer-motion";

interface DataTableProps<TData, TValue> {
  columns: ColumnDef<TData, TValue>[];
  data: TData[];
  searchKey?: string;
  searchPlaceholder?: string;
  isLoading?: boolean;
}

export function DataTable<TData, TValue>({
  columns,
  data,
  searchKey,
  searchPlaceholder = "Tìm kiếm...",
  isLoading = false,
}: DataTableProps<TData, TValue>) {
  const [sorting, setSorting] = useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);

  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    onSortingChange: setSorting,
    getSortedRowModel: getSortedRowModel(),
    onColumnFiltersChange: setColumnFilters,
    getFilteredRowModel: getFilteredRowModel(),
    state: {
      sorting,
      columnFilters,
    },
  });

  return (
    <div className="space-y-4">
      {searchKey && (
        <div className="flex items-center gap-2 max-w-sm">
          <div className="relative w-full">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-[#555]" />
            <Input
              placeholder={searchPlaceholder}
              value={(table.getColumn(searchKey)?.getFilterValue() as string) ?? ""}
              onChange={(event) =>
                table.getColumn(searchKey)?.setFilterValue(event.target.value)
              }
              className="pl-9 bg-[#0A0A0A] border-[#1a1a1a] text-[#ededed] placeholder:text-[#555] focus-visible:ring-0 focus-visible:border-[#333] text-[13px] h-9 rounded-md transition-colors"
            />
          </div>
        </div>
      )}

      <motion.div 
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, delay: 0.2, ease: "easeOut" }}
        className="border border-[#222] bg-[#000000] overflow-hidden shadow-[4px_4px_0_#222]"
      >
        <Table>
          <TableHeader className="bg-[#050505] border-b border-[#222]">
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id} className="hover:bg-transparent border-b border-[#222]">
                {headerGroup.headers.map((header) => {
                  return (
                    <TableHead key={header.id} className="text-[#888] font-medium text-[12px] h-10 px-4">
                      {header.isPlaceholder
                        ? null
                        : flexRender(
                            header.column.columnDef.header,
                            header.getContext()
                          )}
                    </TableHead>
                  );
                })}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && "selected"}
                  className="hover:bg-[#0A0A0A] border-b border-[#222] transition-all duration-200 hover:shadow-[inset_2px_0_0_#c084fc]"
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id} className="px-4 py-3 text-[13px] text-[#ededed]">
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-24 text-center text-[#666] text-[13px]">
                  Không có dữ liệu
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </motion.div>

      <div className="flex items-center justify-between px-1">
        <div className="text-[12px] text-[#666]">
          Hiển thị trang {table.getState().pagination.pageIndex + 1} /{" "}
          {table.getPageCount() || 1}
        </div>
        <div className="flex items-center space-x-2">
          <Button
            variant="outline"
            className="hidden h-9 w-9 p-0 lg:flex border-[#222] hover:border-[#c084fc] hover:bg-[#111] hover:text-[#c084fc] bg-[#000000] transition-colors rounded-none shadow-[2px_2px_0_#222] active:translate-x-[2px] active:translate-y-[2px] active:shadow-none"
            onClick={() => table.setPageIndex(0)}
            disabled={!table.getCanPreviousPage()}
          >
            <ChevronsLeft className="h-4 w-4" />
          </Button>
          <Button
            variant="outline"
            className="h-9 w-9 p-0 border-[#222] hover:border-[#c084fc] hover:bg-[#111] hover:text-[#c084fc] bg-[#000000] transition-colors rounded-none shadow-[2px_2px_0_#222] active:translate-x-[2px] active:translate-y-[2px] active:shadow-none"
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage()}
          >
            <ChevronLeft className="h-4 w-4" />
          </Button>
          <Button
            variant="outline"
            className="h-9 w-9 p-0 border-[#222] hover:border-[#c084fc] hover:bg-[#111] hover:text-[#c084fc] bg-[#000000] transition-colors rounded-none shadow-[2px_2px_0_#222] active:translate-x-[2px] active:translate-y-[2px] active:shadow-none"
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage()}
          >
            <ChevronRight className="h-4 w-4" />
          </Button>
          <Button
            variant="outline"
            className="hidden h-9 w-9 p-0 lg:flex border-[#222] hover:border-[#c084fc] hover:bg-[#111] hover:text-[#c084fc] bg-[#000000] transition-colors rounded-none shadow-[2px_2px_0_#222] active:translate-x-[2px] active:translate-y-[2px] active:shadow-none"
            onClick={() => table.setPageIndex(table.getPageCount() - 1)}
            disabled={!table.getCanNextPage()}
          >
            <ChevronsRight className="h-4 w-4" />
          </Button>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useRef } from "react";
import { Badge } from "@/components/ui/badge";
import { X, Plus, ChevronDown } from "lucide-react";
import { useAdminTags } from "@/hooks/admin/useAdminTags";
import { logger } from "@/lib/utils/logger";

interface TagPickerProps {
  selectedIds: number[];
  onChange: (ids: number[]) => void;
}

function toSlug(str: string) {
  return str
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)+/g, "");
}

export function TagPicker({ selectedIds, onChange }: TagPickerProps) {
  const { tags, isLoading, createTag, updateTag, deleteTag } = useAdminTags();
  const [inputValue, setInputValue] = useState("");
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const selectedTags = tags.filter((t) => selectedIds.includes(t.id));
  const availableTags = tags.filter(
    (t) => !selectedIds.includes(t.id) && t.name.toLowerCase().includes(inputValue.toLowerCase())
  );

  const handleSelect = (id: number) => {
    onChange([...selectedIds, id]);
    setInputValue("");
  };

  const handleRemove = (id: number) => {
    onChange(selectedIds.filter((t) => t !== id));
  };

  const handleCreate = async () => {
    if (!inputValue.trim()) return;
    try {
      const slug = toSlug(inputValue);
      const newTag = await createTag.mutateAsync({ name: inputValue, slug });
      onChange([...selectedIds, newTag.id]);
      setInputValue("");
    } catch (error) {
      logger.error("[TagPicker] Failed to create tag:", error);
    }
  };

  return (
    <div className="relative" ref={containerRef}>
      <div
        className={`flex items-center justify-between min-h-12 w-full rounded-none border-2 px-3 py-2 text-[12px] font-medium transition-colors cursor-pointer shadow-[inset_2px_2px_0_#000] hover:border-[#c084fc] ${
          isOpen ? "outline-none border-[#c084fc] bg-[#111]" : "border-[#222] bg-[#111]"
        }`}
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex flex-wrap items-center gap-2">
          {selectedTags.length === 0 ? (
            <span className="text-[#666] font-bold uppercase tracking-widest text-[10px]">Chọn thẻ (Tag)...</span>
          ) : (
            selectedTags.map((tag) => (
              <Badge key={tag.id} variant="secondary" className="gap-1 px-2 py-1 text-[10px] font-black uppercase tracking-widest bg-[#c084fc] text-black rounded-none border-2 border-[#222] shadow-[2px_2px_0_#222] hover:bg-[#a855f7] hover:shadow-none hover:translate-x-[2px] hover:translate-y-[2px] transition-all">
                {tag.name}
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleRemove(tag.id);
                  }}
                  className="ml-1 hover:bg-[#222] hover:text-[#fff] rounded-full p-0.5 transition-colors cursor-pointer"
                >
                  <X size={12} />
                </button>
              </Badge>
            ))
          )}
        </div>
        <ChevronDown size={16} className={`text-[#888] shrink-0 ml-2 transition-transform ${isOpen ? "rotate-180 text-[#c084fc]" : ""}`} />
      </div>

      {isOpen && (
        <div className="absolute z-10 w-full mt-2 bg-[#000] border-2 border-[#222] rounded-none shadow-[4px_4px_0_#222] flex flex-col">
          <div className="p-2 border-b-2 border-[#222] bg-[#0A0A0A]">
            <input
              className="w-full bg-[#111] border-2 border-[#222] px-3 py-2 text-[#fff] font-medium text-[12px] outline-none focus:border-[#c084fc] rounded-none"
              placeholder="Tìm hoặc tạo thẻ mới..."
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  e.preventDefault();
                  if (availableTags.length > 0) {
                    handleSelect(availableTags[0].id);
                  } else {
                    handleCreate();
                  }
                }
              }}
              autoFocus
            />
          </div>
          <div className="max-h-[200px] overflow-auto">
            {availableTags.map((tag) => (
              <div
                key={tag.id}
                className="px-4 py-3 hover:bg-[#c084fc] hover:text-black text-[#fff] font-medium text-[12px] transition-colors cursor-pointer border-b border-[#222] last:border-0"
                onClick={() => handleSelect(tag.id)}
              >
                {tag.name}
              </div>
            ))}
            {availableTags.length === 0 && inputValue && (
              <div
                className="px-4 py-3 hover:bg-[#c084fc] hover:text-black text-[#c084fc] font-bold text-[12px] transition-colors cursor-pointer flex items-center gap-2 border-b border-[#222] last:border-0"
                onClick={handleCreate}
              >
                <Plus size={16} /> Tạo thẻ mới &quot;{inputValue}&quot;
              </div>
            )}
            {availableTags.length === 0 && !inputValue && (
              <div className="px-4 py-3 text-[#666] italic text-[12px]">
                Không còn thẻ nào để chọn
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useRef, ChangeEvent, DragEvent } from "react";
import { UploadCloud, Image as ImageIcon, X, Loader2 } from "lucide-react";
import { uploadsService } from "@/lib/services/uploadsService";
import { toast } from "sonner";
import Image from "next/image";
import { Button } from "@/components/ui/button";

interface ImageUploadProps {
  value?: string;
  onChange: (url: string) => void;
  onRemove?: () => void;
  className?: string;
}

export function ImageUpload({ value, onChange, onRemove, className = "" }: ImageUploadProps) {
  const [isUploading, setIsUploading] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = async (e: ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      await uploadFile(file);
    }
  };

  const uploadFile = async (file: File) => {
    // Validate file type
    if (!file.type.startsWith("image/")) {
      toast.error("Vui lòng chọn file hình ảnh hợp lệ (JPG, PNG, GIF, WebP)");
      return;
    }
    // FIX: Corrected 2554 -> 1024 (1KB = 1024 bytes, not 2554)
    if (file.size > 5 * 1024 * 1024) {
      toast.error("Kích thước file không được vượt quá 5MB");
      return;
    }

    try {
      setIsUploading(true);
      const url = await uploadsService.uploadFile(file);
      onChange(url);
      toast.success("Tải ảnh lên thành công!");
      } catch (error: unknown) {
        const message = error instanceof Error ? error.message : "Unknown error";
        toast.error("Lỗi khi tải ảnh: " + message);
      } finally {
      setIsUploading(false);
      // Reset input
      if (fileInputRef.current) {
        fileInputRef.current.value = "";
      }
    }
  };

  const handleDragOver = (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = async (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files?.[0];
    if (file) {
      await uploadFile(file);
    }
  };

  return (
    <div className={`w-full ${className}`}>
      {value ? (
        <div className="relative group rounded-xl overflow-hidden border border-border bg-muted/30 aspect-video flex items-center justify-center">
          <Image 
            src={value} 
            alt="Uploaded image" 
            fill
            className="object-contain"
            sizes="(max-width: 768px) 100vw, 50vw"
          />
          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
            <Button 
              type="button" 
              variant="secondary" 
              size="sm" 
              onClick={() => fileInputRef.current?.click()}
            >
              Đổi ảnh
            </Button>
            {onRemove && (
              <Button 
                type="button" 
                variant="destructive" 
                size="sm" 
                onClick={onRemove}
              >
                Xóa
              </Button>
            )}
          </div>
        </div>
      ) : (
        <div
          className={`relative border-2 border-dashed rounded-xl p-8 flex flex-col items-center justify-center gap-4 transition-colors cursor-pointer aspect-video
            ${isDragging ? "border-primary bg-primary/5" : "border-muted-foreground/25 hover:border-primary/50 hover:bg-muted/30"}
            ${isUploading ? "opacity-50 pointer-events-none" : ""}`}
          onClick={() => !isUploading && fileInputRef.current?.click()}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          {isUploading ? (
            <div className="flex flex-col items-center text-primary">
              <Loader2 className="w-10 h-10 animate-spin mb-4" />
              <p className="font-medium">Đang tải ảnh lên...</p>
            </div>
          ) : (
            <>
              <div className="p-4 rounded-full bg-primary/10 text-primary">
                <UploadCloud className="w-8 h-8" />
              </div>
              <div className="text-center space-y-1">
                <p className="font-medium text-foreground">
                  Kéo thả ảnh vào đây hoặc click để chọn file
                </p>
                <p className="text-sm text-muted-foreground">
                  Hỗ trợ JPG, PNG, GIF, WebP (Tối đa 5MB)
                </p>
              </div>
            </>
          )}
        </div>
      )}

      <input
        ref={fileInputRef}
        type="file"
        accept="image/jpeg, image/png, image/gif, image/webp"
        className="hidden"
        onChange={handleFileSelect}
      />
    </div>
  );
}

