"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Loader2, Lock, Mail, User } from "lucide-react";
import { createSafeZodResolver } from "@/lib/utils/safeZodResolver";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  baseSchema,
  registerSchema,
  type AuthFormValues,
  type AuthFormProps,
} from "@/types/iAccount";

export type { AuthFormValues };

export function AuthForm({
  submitLabel,
  switchText,
  switchHref,
  showUsernameField = false,
  showProviders = true,
  onSubmit,
}: AuthFormProps) {
  const schema = showUsernameField ? registerSchema : baseSchema;
  const [isSubmitting, setIsSubmitting] = useState(false);

  const {
    handleSubmit,
    register,
    formState: { errors },
  } = useForm<AuthFormValues>({
    resolver: createSafeZodResolver(schema),
    mode: "onSubmit",
    reValidateMode: "onBlur",
    shouldFocusError: true,
    defaultValues: {
      email: "",
      password: "",
      remember: true,
      username: showUsernameField ? "" : undefined,
    },
  });

  const onInternalSubmit = async (values: AuthFormValues) => {
    try {
      setIsSubmitting(true);
      await onSubmit?.(values);
    } finally {
      setIsSubmitting(false);
    }
  };

  const [primarySwitchText, secondarySwitchText] = switchText?.split("?") ?? [];
  const hasSecondary = typeof secondarySwitchText !== "undefined";

  return (
    <div className="space-y-6">
      <form className="space-y-5" onSubmit={handleSubmit(onInternalSubmit)} noValidate>
        {showUsernameField && (
          <>
            <div className="space-y-2">
              <Label htmlFor="username">Username</Label>
              <div className="relative">
                <User className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground/60" />
                <Input id="username" placeholder="username" className="pl-10" {...register("username")} />
              </div>
              {errors.username && <p className="text-sm text-rose-500">{errors.username.message}</p>}
            </div>

            <div className="space-y-2">
              <Label htmlFor="fullName">Họ và tên</Label>
              <div className="relative">
                <User className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground/60" />
                <Input id="fullName" placeholder="Nguyễn Văn A" className="pl-10" {...register("fullName")} />
              </div>
              {errors.fullName && <p className="text-sm text-rose-500">{errors.fullName.message}</p>}
            </div>

            <div className="space-y-2">
              <Label htmlFor="phoneNumber">Số điện thoại</Label>
              <div className="relative">
                <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground/60">
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="20" x="5" y="2" rx="2" ry="2"/><path d="M12 18h.01"/></svg>
                </span>
                <Input id="phoneNumber" type="tel" placeholder="0912345678" className="pl-10" {...register("phoneNumber")} />
              </div>
              {errors.phoneNumber && <p className="text-sm text-rose-500">{errors.phoneNumber.message}</p>}
            </div>
          </>
        )}

        <div className="space-y-2">
          <Label htmlFor="email">Email</Label>
          <div className="relative">
            <Mail className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground/60" />
            <Input
              id="email"
              type="email"
              placeholder="ban@example.com"
              className="pl-10"
              autoComplete="email"
              {...register("email")}
            />
          </div>
          {errors.email && <p className="text-sm text-rose-500">{errors.email.message}</p>}
        </div>

        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <Label htmlFor="password">Mật khẩu</Label>
            {!showUsernameField && (
              <Link
                href="/forgot-password"
                className="text-sm font-medium text-muted-foreground hover:text-primary transition-colors"
                tabIndex={-1}
              >
                Quên mật khẩu?
              </Link>
            )}
          </div>
          <div className="relative">
            <Lock className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground/60" />
            <Input
              id="password"
              type="password"
              placeholder="••••••••"
              className="pl-10"
              autoComplete={showUsernameField ? "new-password" : "current-password"}
              {...register("password")}
            />
          </div>
          {errors.password && <p className="text-sm text-rose-500">{errors.password.message}</p>}
        </div>

        {showUsernameField && (
          <div className="space-y-2">
            <Label htmlFor="confirmPassword">Xác nhận mật khẩu</Label>
            <div className="relative">
              <Lock className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground/60" />
              <Input
                id="confirmPassword"
                type="password"
                placeholder="••••••••"
                className="pl-10"
                autoComplete="new-password"
                {...register("confirmPassword")}
              />
            </div>
            {errors.confirmPassword && <p className="text-sm text-rose-500">{errors.confirmPassword.message}</p>}
          </div>
        )}

        <Button type="submit" className="mt-2 w-full rounded-full font-semibold" disabled={isSubmitting}>
          {isSubmitting ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              Đang xử lý...
            </>
          ) : (
            submitLabel
          )}
        </Button>
      </form>

      {showProviders && (
        <div className="space-y-3">
          <div className="flex items-center gap-3 text-xs uppercase tracking-[0.35em] text-muted-foreground">
            <span className="h-px flex-1 bg-border" />
            hoặc
            <span className="h-px flex-1 bg-border" />
          </div>
        </div>
      )}

      {switchText && switchHref && (
        <p className="text-center text-sm text-muted-foreground">
          {hasSecondary ? `${primarySwitchText}?` : switchText}
          <Link href={switchHref} className="ml-1 font-semibold text-[color:var(--title)] hover:underline">
            {hasSecondary ? secondarySwitchText?.trim() : "Tạo tài khoản"}
          </Link>
        </p>
      )}
    </div>
  );
}

"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { Lock, LogIn, Crown, ArrowLeft } from "lucide-react";
import { Button } from "@/components/ui/button";
import type { Plan } from "@/types/iAccount";
import type { ArticlePlan } from "@/types/iReport";
import { canUserAccessArticle, getArticleMaxPlanLevel } from "@/lib/utils/planAccess";

interface ArticleAccessOverlayProps {
  userPlan: Plan | null;
  articlePlans: ArticlePlan[];
  isAuthenticated: boolean;
  articleTitle: string;
}

export function ArticleAccessOverlay({
  userPlan,
  articlePlans,
  isAuthenticated,
  articleTitle,
}: ArticleAccessOverlayProps) {
  const router = useRouter();
  
  // Nếu article không có plan yêu cầu → không cần overlay
  const articleMaxLevel = getArticleMaxPlanLevel(articlePlans);
  if (articleMaxLevel === 0) {
    return null;
  }

  // Kiểm tra quyền truy cập
  const hasAccess = canUserAccessArticle(userPlan, articlePlans);

  // Nếu có quyền → không hiển thị overlay
  if (hasAccess) {
    return null;
  }

  // Lấy plan yêu cầu cao nhất
  const requiredPlan = articlePlans
    .sort((a, b) => (b.level || 0) - (a.level || 0))[0];

  const handleGoBack = () => {
    router.back();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/95 backdrop-blur-sm">
      <div className="relative w-full max-w-2xl mx-4 p-8 rounded-3xl border border-border/40 bg-card/90 backdrop-blur-md shadow-2xl">
        {/* Nút Quay lại ở góc trên bên trái */}
    
        
        <div className="text-center space-y-6 pt-2">
          {/* Icon */}
          <div className="flex justify-center">
            <div className="relative">
              <div className="absolute inset-0 bg-primary/20 rounded-full blur-xl" />
              <div className="relative p-4 rounded-full bg-primary/10 border-2 border-primary/30">
                {isAuthenticated ? (
                  <Crown className="h-12 w-12 text-primary" />
                ) : (
                  <Lock className="h-12 w-12 text-primary" />
                )}
              </div>
            </div>
          </div>

          {/* Title */}
          <div className="space-y-2">
            <h2 className="text-3xl font-bold text-foreground">
              {isAuthenticated
                ? "Nâng cấp gói để xem nội dung này"
                : "Đăng nhập để xem nội dung"}
            </h2>
            <p className="text-muted-foreground text-lg">
              {isAuthenticated
                ? `Bài viết "${articleTitle}" yêu cầu gói ${requiredPlan.name || "Premium"} trở lên`
                : "Vui lòng đăng nhập để tiếp tục xem nội dung"}
            </p>
          </div>

          {/* Plan badges */}
          {articlePlans.length > 0 && (
            <div className="flex flex-wrap justify-center gap-2">
              {articlePlans.map((plan) => (
                <span
                  key={plan.id}
                  className="inline-flex items-center rounded-full border border-primary/30 px-4 py-2 text-sm font-semibold text-primary bg-primary/10"
                >
                  {plan.name}
                </span>
              ))}
            </div>
          )}

          {/* Actions */}
          <div className="flex flex-col sm:flex-row gap-4 justify-center items-center pt-4 w-full">
            {isAuthenticated ? (
              <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
                <Button
                  size="lg"
                  variant="outline"
                  onClick={handleGoBack}
                  className="border-2 bg-background hover:bg-muted hover:border-primary/50 w-full sm:w-auto sm:min-w-[140px]"
                >
                  Quay lại
                </Button>
                <Button asChild size="lg" className="bg-primary hover:bg-primary/90 w-full sm:w-auto sm:min-w-[180px]">
                  <Link href="/goi-hoi-vien" className="flex items-center justify-center">
                    <Crown className="mr-2 h-5 w-5" />
                    Nâng cấp ngay
                  </Link>
                </Button>
              </div>
            ) : (
              <>
                <Button
                  size="lg"
                  variant="outline"
                  onClick={handleGoBack}
                >
                  Quay lại
                </Button>
                <Button asChild size="lg" variant="outline">
                  <Link href="/">Về trang chủ</Link>
                </Button>
                <Button asChild size="lg" className="bg-primary hover:bg-primary/90">
                  <Link href="/login">
                    <LogIn className="mr-2 h-5 w-5" />
                    Đăng nhập
                  </Link>
                </Button>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

