import axios, {
  AxiosError,
  AxiosInstance,
  InternalAxiosRequestConfig,
} from "axios";
import { handleExpiredToken } from "@/lib/utils/authHandler";
import { normalizeUrl, buildApiBaseUrl } from "@/lib/utils/url";
import { logger } from "@/lib/utils/logger";
import { getClientCookie, setAuthCookies } from "@/lib/utils/cookies";

const DEFAULT_HEADERS = {
  "Content-Type": "application/json",
} as const;

let cachedBaseURL: string | null = null;
let cacheTimestamp = 0;
const CACHE_TTL = 60000;

function getBackendBaseURL(forceRefresh = false): string {
  const now = Date.now();
  if (!forceRefresh && cachedBaseURL !== null && now - cacheTimestamp < CACHE_TTL) {
    return cachedBaseURL;
  }

  let primaryApiHost = normalizeUrl(process.env.NEXT_PUBLIC_API_URL);
  let fallbackApiHost = normalizeUrl(process.env.NEXT_PUBLIC_DEV_API_URL);

  const isServer = typeof window === "undefined";

  if (isServer) {
    if (primaryApiHost.startsWith("/")) {
      primaryApiHost = `http://127.0.0.1:3000${primaryApiHost}`;
    }
    if (fallbackApiHost.startsWith("/")) {
      fallbackApiHost = `http://127.0.0.1:3000${fallbackApiHost}`;
    }
  }

  const apiBaseUrl = primaryApiHost || fallbackApiHost;
  const baseURL = buildApiBaseUrl(apiBaseUrl);

  cachedBaseURL = baseURL;
  cacheTimestamp = now;

  return baseURL;
}

async function getToken(): Promise<string | null> {
  if (typeof window !== "undefined") {
    return getClientCookie("auth_token");
  } else {
    try {
      const { cookies } = await import("next/headers");
      const cookieStore = await cookies();
      const token = cookieStore.get("auth_token");
      return token ? token.value : null;
    } catch {
      return null;
    }
  }
}

async function getRefreshToken(): Promise<string | null> {
  if (typeof window !== "undefined") {
    return getClientCookie("refresh_token");
  } else {
    try {
      const { cookies } = await import("next/headers");
      const cookieStore = await cookies();
      const token = cookieStore.get("refresh_token");
      return token ? token.value : null;
    } catch {
      return null;
    }
  }
}

let isRefreshing = false;
let failedQueue: Array<{ resolve: (value?: unknown) => void; reject: (reason?: unknown) => void }> = [];

const processQueue = (error: unknown, token: string | null = null) => {
  failedQueue.forEach((prom) => {
    if (error) prom.reject(error);
    else prom.resolve(token);
  });
  failedQueue = [];
};

function createRequestInterceptor(client: AxiosInstance) {
  return async (config: InternalAxiosRequestConfig) => {
    if (typeof window === "undefined") {
      config.baseURL = getBackendBaseURL(true);
    }

    const token = await getToken();
    if (token && config.headers) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    return config;
  };
}

function createResponseInterceptor(client: AxiosInstance) {
  return async (error: AxiosError) => {
    const originalRequest = error.config as InternalAxiosRequestConfig & { _retry?: boolean };

    if (error.response?.status === 401 && originalRequest && !originalRequest._retry) {
      const url = originalRequest.url || "";
      const isAuthEndpoint = url.includes("/auth/login") || url.includes("/auth/refresh");

      if (isAuthEndpoint) {
        return Promise.reject(error);
      }

      if (isRefreshing) {
        return new Promise(function (resolve, reject) {
          failedQueue.push({ resolve, reject });
        })
          .then((token) => {
            originalRequest.headers.Authorization = "Bearer " + token;
            return client(originalRequest);
          })
          .catch((err) => Promise.reject(err));
      }

      originalRequest._retry = true;
      isRefreshing = true;

      try {
        const refreshToken = await getRefreshToken();
        if (!refreshToken) throw new Error("No refresh token available");

        const baseURL = getBackendBaseURL();
        const { data } = await axios.post(`${baseURL}/auth/refresh`, {
          refreshToken: refreshToken,
          refresh_token: refreshToken, // keep snake_case just in case
        });

        const newAccessToken = data?.accessToken || data?.access_token;
        const newRefreshToken = data?.refreshToken || data?.refresh_token;

        if (newAccessToken) {
          setAuthCookies(newAccessToken, newRefreshToken);

          client.defaults.headers.common["Authorization"] = "Bearer " + newAccessToken;
          originalRequest.headers.Authorization = "Bearer " + newAccessToken;

          processQueue(null, newAccessToken);
          return client(originalRequest);
        } else {
          throw new Error("Refresh failed");
        }
      } catch (refreshError) {
        processQueue(refreshError, null);
        if (typeof window !== "undefined") {
          await handleExpiredToken();
        }
        return Promise.reject(refreshError);
      } finally {
        isRefreshing = false;
      }
    }

    return Promise.reject(error);
  };
}

// Authenticated client — used for all API calls that require authentication
export const backendClient: AxiosInstance = axios.create({
  baseURL: "/api/v1",
  withCredentials: true,
  headers: DEFAULT_HEADERS,
  timeout: 30000,
});

backendClient.interceptors.request.use(
  createRequestInterceptor(backendClient),
  (error) => Promise.reject(error),
);

backendClient.interceptors.response.use(
  (response) => response,
  createResponseInterceptor(backendClient),
);

// Public client — used for public endpoints (no auth token attachment needed)
// NOTE: Only use this for truly public endpoints. Most endpoints require auth.
export const appClient: AxiosInstance = axios.create({
  baseURL: "/api/v1",
  withCredentials: true,
  headers: DEFAULT_HEADERS,
  timeout: 30000,
});

// FIX: Attach JWT token to appClient so it's not always unauthenticated
appClient.interceptors.request.use(
  createRequestInterceptor(appClient),
  (error) => Promise.reject(error),
);

appClient.interceptors.response.use(
  (response) => response,
  createResponseInterceptor(appClient),
);

export function invalidateBaseURLCache(): void {
  cachedBaseURL = null;
  cacheTimestamp = 0;
}

import { backendClient } from "@/lib/http/httpClient";
import { env } from "@/lib/env";
import type {
  Article,
  ArticleCategorySlug,
  ArticleDetail,
  ArticleDetailApiResponse,
  PaginatedArticlesResponse,
  ApiArticleListItem,
  ApiArticleDetail,
} from "@/types/iReport";

const DEFAULT_COVER_FALLBACK = "/homePage/banner.jpg";

const buildMediaUrl = (path?: string | null) => {
  if (!path) return null;
  if (path.startsWith("http")) return path;
  if (!env.mediaBaseUrl) return path;
  return `${env.mediaBaseUrl}${path}`;
};

const normalizeArticleBlocks = (value: ApiArticleDetail["contentBlocks"] | ApiArticleDetail["blocks"]) => {
  if (!value) return [];

  if (Array.isArray(value)) return value;

  return value.blocks ?? value.data ?? value.items ?? [];
};

const normalizeArticle = (article: ApiArticleListItem): Article => {
  const coverUrl = buildMediaUrl(article.coverUrl) ?? DEFAULT_COVER_FALLBACK;
  const primaryTag = article.tag ?? article.tags?.[0] ?? null;

  return {
    id: article.id,
    documentId: String(article.id), // Fallback since NestJS doesn't use documentId
    title: article.title,
    description: article.description ?? "",
    slug: article.slug,
    createdAt: article.createdAt,
    updatedAt: article.updatedAt,
    publishedAt: article.publishedAt ?? article.createdAt,
    plans: [], // List item doesn't return plans in NestJS usually, or we can map it if needed
    category: article.category ? {
      id: article.category.id,
      documentId: String(article.category.id),
      name: article.category.name,
      slug: article.category.slug as ArticleCategorySlug,
      description: "",
      createdAt: article.createdAt,
      updatedAt: article.updatedAt,
      publishedAt: article.createdAt,
    } : null,
    tag: primaryTag ? {
      id: primaryTag.id,
      documentId: String(primaryTag.id),
      name: primaryTag.name,
      createdAt: article.createdAt,
      updatedAt: article.updatedAt,
      publishedAt: article.createdAt,
    } : null,
    cover: article.coverUrl ? { url: article.coverUrl } : null,
    coverUrl,
  };
};

const buildArticleUrl = (category: ArticleCategorySlug, limit?: number) => {
  const url = `/articles`;
  const params = new URLSearchParams();
  if (category && category !== "all") {
    params.append("category", category);
  }
  if (limit) {
    params.append("limit", String(limit));
  }
  const qs = params.toString();
  return qs ? `${url}?${qs}` : url;
};

const buildArticleDetailUrl = (slug: string) => `/articles/${slug}`;

const normalizeArticleDetail = (article: ApiArticleDetail): ArticleDetail => {
  const normalized = normalizeArticle(article);

  return {
    ...normalized,
    plans: article.plans ? article.plans.map(p => ({
      id: p.planId,
      documentId: String(p.planId),
      name: p.plan.slug,
      level: p.plan.level,
      createdAt: normalized.createdAt,
      updatedAt: normalized.updatedAt,
      publishedAt: normalized.publishedAt,
    })) : [],
    blocks: normalizeArticleBlocks(article.contentBlocks ?? article.blocks),
    author: article.author ? {
      id: article.author.id,
      documentId: String(article.author.id),
      name: article.author.name ?? article.author.username ?? "Ẩn danh",
      createdAt: normalized.createdAt,
      updatedAt: normalized.updatedAt,
      publishedAt: normalized.publishedAt,
    } : null,
  };
};

export const getArticlesByCategory = async (
  category: ArticleCategorySlug,
  limit?: number,
): Promise<Article[]> => {
  const { data: payload } = await backendClient.get<PaginatedArticlesResponse>(
    buildArticleUrl(category, limit),
  );

  const articles = payload?.data ?? [];
  return articles.map(normalizeArticle);
};

export const getArticleBySlug = async (
  slug: string,
): Promise<ArticleDetail | null> => {
  try {
    const { data: article } = await backendClient.get<ApiArticleDetail>(
      buildArticleDetailUrl(slug),
    );

    if (!article) return null;
    return normalizeArticleDetail(article);
  } catch (error) {
    const err = error as { response?: { status?: number } };
    if (err.response?.status === 404) return null;
    throw error;
  }
};

import { backendClient } from "@/lib/http/httpClient";

export interface PresignRequest {
  filename: string;
  contentType: string;
}

export interface PresignResponse {
  uploadUrl: string;
  key: string;
  fileUrl: string;
}

export const uploadsService = {
  /**
   * Upload a file directly to the local Next.js API route (/api/upload)
   * This saves the file into public/uploads folder like Strapi.
   */
  async uploadFile(file: File): Promise<string> {
    const formData = new FormData();
    formData.append('file', file);

    const res = await fetch('/api/upload', {
      method: 'POST',
      body: formData,
    });

    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.error || `Upload failed: ${res.statusText}`);
    }

    const data = (await res.json()) as { url: string };
    return data.url;
  }
};

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { setAuthCookies, clearAuthCookies, getClientCookie } from './cookies';

describe('cookies utility', () => {
  beforeEach(() => {
    // Clear all cookies before each test
    if (typeof document !== 'undefined') {
      const cookies = document.cookie.split(';');
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i];
        const eqPos = cookie.indexOf('=');
        const name = eqPos > -1 ? cookie.substring(0, eqPos).trim() : cookie.trim();
        if (name) {
          document.cookie = `${name}=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT`;
        }
      }
    }
  });

  it('should set auth cookies correctly', () => {
    setAuthCookies('accessToken123', 'refreshToken456');

    expect(getClientCookie('auth_token')).toBe('accessToken123');
    expect(getClientCookie('refresh_token')).toBe('refreshToken456');
  });

  it('should get client cookie by name', () => {
    document.cookie = 'test_cookie=value123; path=/';
    expect(getClientCookie('test_cookie')).toBe('value123');
    expect(getClientCookie('non_existent')).toBeNull();
  });

  it('should clear auth cookies', () => {
    setAuthCookies('accessToken123', 'refreshToken456');
    document.cookie = 'sidebar_state=expanded; path=/';

    expect(getClientCookie('auth_token')).toBe('accessToken123');
    expect(getClientCookie('refresh_token')).toBe('refreshToken456');
    expect(getClientCookie('sidebar_state')).toBe('expanded');

    clearAuthCookies();

    // JSDOM has some limitations with domains, but basic clearance on root should work.
    expect(getClientCookie('auth_token')).toBeNull();
    expect(getClientCookie('refresh_token')).toBeNull();
  });
});

/**
 * Utility functions for portfolio access control
 */
import { PORTFOLIO_TIERS, TIER_ALLOWED_PLANS, type PortfolioTier } from "@/lib/constants/portfolio";

/**
 * Check if user's plan can access a specific tier page
 */
export function canAccessTierPage(userPlan: PortfolioTier | null, targetTier: PortfolioTier): boolean {
  if (!userPlan) return false;
  const allowedPlans = TIER_ALLOWED_PLANS[targetTier];
  return allowedPlans.includes(userPlan);
}

/**
 * Get allowed plans for a tier page
 */
export function getAllowedPlansForTier(tier: PortfolioTier): PortfolioTier[] {
  return TIER_ALLOWED_PLANS[tier];
}
